#include<bits/stdc++.h>
using namespace std;
vector<int> p[101];
int a[101];
bool dfs(int x)
{
	if(a[x]>0)
	{
		a[x]--;
		return true; 
	}
	if(p[x].empty())
	{
		if(a[x]>0)
		{
			a[x]--;
			return true;
		}
		else
		{
			return false;
		}
	}
	int s=p[x].size();
	for(int i=0;i<s;i++)
	{
		if(a[p[x][i]]>0)
		{
			a[p[x][i]]--;
		}
		else
		{
			if(!dfs(p[x][i]))
			{
				return false;
			}
		}
	}
	return true;
}
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	int k;
	scanf("%d",&k);
	for(int i=1;i<=k;i++)
	{
		int l,m;
		scanf("%d%d",&l,&m);
		for(int j=1;j<=m;j++)
		{
			int temp;
			scanf("%d",&temp);
			p[l].push_back(temp);
		}
	}
	int ans=0;
	while(dfs(n))
	{
		ans++;
	}
	ans+=a[n]; 
	printf("%d",ans);
	return 0;
}
